#!/usr/bin/env bash
set -ex

# Parse --force option
parse_args() { 
    FORCE=false
    while [[ $# -gt 0 ]]; do
        key="$1"
        case $key in
            --force)
                FORCE=true
                shift
            ;;
            --cicd)
                CICD=true
                shift
            ;;
            *)
                echo "Unknown option $1 passed"
                shift
            ;;
        esac
    done
}

# Check if build artifacts exist, if so, terminate script/job
artifact_check() {
    if [ "${FORCE}" = false ]; then
        if [ "$CI_PIPELINE_SOURCE" == "push" ] || [ "$CI_PIPELINE_SOURCE" == "merge_request_event" ]; then
            PKGRESP=$(curl --write-out "%{http_code}" --silent --output /dev/null --head -H "JOB-TOKEN: ${CI_JOB_TOKEN}" "${ARTIFACTS_URL}/${FULL_FILE_NAME}")
            if [ $PKGRESP == "200" ]; then
                echo "Artifact already exists for this commit. Skipping the job. You may execute the job by running the pipeline manually"
                exit 200
            fi
        fi
    fi
}

parse_args "$@"

if [ -z "$CI_COMMIT_SHORT_SHA" ]; then
    echo "Missing GitLab Commit SHA env variable. Using HEAD instead..."
    CI_COMMIT_SHORT_SHA=$(git rev-parse --short HEAD)
fi

FILE_NAME=corellium-cli
FULL_FILE_NAME=${CI_COMMIT_SHA}-${FILE_NAME}-build.tar.gz
ARTIFACTS_URL="${CI_API_V4_URL}/projects/${CI_PROJECT_ID}/packages/generic/${CI_PROJECT_NAME}/artifacts"

artifact_check

# This script is executed from the $REPO/ci folder, but we need to get to the repo root
SCRIPT_DIR=$(cd -- "$(dirname -- "${BASH_SOURCE:-0}")" &>/dev/null && pwd)
CORES=8
EXTRAS_DIR=/home/corellium/compute-extras
SYSROOT=/opt/ubuntu-arm64-sysroot
OUTPUT_DIR="${SCRIPT_DIR}/../output"

mkdir -p ${OUTPUT_DIR}


if [ "${CICD}" = true ]; then
    TMP_REPO_DIR="/tmp/corellium-packaging-staging-compute"
    mkdir -p "${TMP_REPO_DIR}"
else
    TMP_REPO_DIR=$(mktemp -d /tmp/corellium-packaging-staging-compute-XXXXXXXXXX)
fi

TMPROOT=${TMP_REPO_DIR}/build-sysroot
DEST_DIR=${TMP_REPO_DIR}/${FILE_NAME}

mkdir -p ${TMPROOT}

cp -a ${SYSROOT}/* ${TMPROOT}/

echo "Starting build for ${FILE_NAME} on ${CI_COMMIT_BRANCH}"

function build() {
    # To start the build we need to move up one level from $repo/jenkinsbuild to just the $repo root
    cd "$SCRIPT_DIR"
    cd ..

    mkdir -p ${DEST_DIR}
    repo_folder="${DEST_DIR}/usr/share/corellium/corellium-cli/"
    git checkout-index -a -f --prefix="$repo_folder"


    # BEGIN inside build folder
    pushd "$repo_folder"
      cli_version=$(jq .version --raw-output < package.json)
      corellium_cli_tarball="corellium-corellium-cli-$cli_version.tgz"

      node --version
      npm ci --unsafe-perm --ignore-scripts
      npm pack

      # Grab the packed tgz, move it up to a temporary file `tarred-ball`
      # and replace the contents of corellium-cli with the tarball so it's ok to distribute
      cp ${repo_folder}${corellium_cli_tarball} ${DEST_DIR}/usr/share/corellium/tarred-ball
      rm -rf "$repo_folder"
      mkdir -p "$repo_folder"
      mv ${DEST_DIR}/usr/share/corellium/tarred-ball "$repo_folder/$corellium_cli_tarball"
      ln -sf "${corellium_cli_tarball}" "${repo_folder}/corellium-cli-latest.tgz"

      # bundle together the built folder
      pushd $DEST_DIR
      fakeroot tar -czf ${OUTPUT_DIR}/${FULL_FILE_NAME} .
      popd

      rm -rf ${DEST_DIR}

      # END inside build folder
    popd
}

build

rm -rf ${TMP_REPO_DIR}
echo "Build for ${FILE_NAME} completed"

# Artifact upload
if [ -z "$CI_JOB_TOKEN" ] || [ -z "$CI_API_V4_URL" ] || [ -z "$CI_PROJECT_ID" ] || [ -z "$CI_PROJECT_NAME" ] || [ -z "$CI_COMMIT_SHA" ]; then
    echo "GitLab environment variables missing. Skipping artifact upload..."
else
    echo "Uploading artifact"
    curl -k --location --fail --upload-file ${OUTPUT_DIR}/${FULL_FILE_NAME} --header "JOB-TOKEN: ${CI_JOB_TOKEN}" "${ARTIFACTS_URL}/${FULL_FILE_NAME}"
fi
